import { Pedido, EstadoPedido } from '../types';

const API_BASE_URL = ''; // En producción el mismo dominio sirve la API

export const apiService = {
  getEnv: () => window.location.hostname === 'localhost' ? 'DEVELOPMENT' : 'PRODUCTION',

  async fetchOrders(): Promise<Pedido[]> {
    try {
      const response = await fetch(`${API_BASE_URL}/api/orders`, {
        headers: { 
          'Accept': 'application/json',
          'Cache-Control': 'no-cache'
        }
      });
      if (!response.ok) throw new Error('Servidor no responde');
      return await response.json();
    } catch (error) {
      console.warn('[API] Fallback a Mock local por error de red.');
      const { mockApi } = await import('./mockApi');
      return await mockApi.getOrders() as Pedido[];
    }
  },

  async assignOrder(orderId: number, driverId: number) {
    try {
      const response = await fetch(`${API_BASE_URL}/api/orders/${orderId}/assign`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ driverId })
      });
      if (!response.ok) throw new Error('Error en asignación remota');
      return await response.json();
    } catch (error) {
      const { mockApi } = await import('./mockApi');
      return await mockApi.assignOrder(orderId, driverId);
    }
  },

  async updateOrder(orderId: number, estado: EstadoPedido) {
    try {
      const response = await fetch(`${API_BASE_URL}/api/orders/${orderId}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ estado })
      });
      if (!response.ok) throw new Error('Error en actualización remota');
      return await response.json();
    } catch (error) {
      const { mockApi } = await import('./mockApi');
      return await mockApi.updateOrderStatus(orderId, estado);
    }
  },

  async getSystemHealth() {
    try {
      const response = await fetch(`${API_BASE_URL}/health`);
      return await response.json();
    } catch {
      return { status: 'OFFLINE', message: 'Conectado a Red Local de Emergencia' };
    }
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import Estructura from './components/Layout';
import MobileSimulator from './components/MobileSimulator';
import SeccionVentasView from './components/SeccionVentasView';
import DriverOnboardingView from './components/DriverOnboardingView';
import StoreOnboardingView from './components/StoreOnboardingView';
import OrderManagementView from './components/OrderManagementView';
import InteractiveMap from './components/InteractiveMap';
import InfrastructureOpsView from './components/VercelOpsView';
import WalletView from './components/WalletView';
import { mockApi } from './services/mockApi';
import { apiService } from './services/apiService';
import { getLogisticsInsights } from './services/geminiService';
import { Pedido, EstadoPedido, SocioRepartidor, Comercio } from './types';

const App: React.FC = () => {
  const [pestañaActiva, setPestañaActiva] = useState('tablero');
  const [pedidos, setPedidos] = useState<Pedido[]>([]);
  const [repartidores, setRepartidores] = useState<SocioRepartidor[]>([]);
  const [comercios, setComercios] = useState<Comercio[]>([]);
  const [cargando, setCargando] = useState(true);
  const [iaInsight, setIaInsight] = useState<string>('Analizando flujos neuronales...');
  const [isSimulatorOpen, setIsSimulatorOpen] = useState(false);
  const [toast, setToast] = useState<{ message: string, type: 'error' | 'success' | 'info' } | null>(null);

  const showToast = (message: string, type: 'error' | 'success' | 'info' = 'info') => {
    setToast({ message, type });
  };

  const fetchData = useCallback(async (isSilent = false) => {
    if (!isSilent) setCargando(true);
    try {
      const o = await apiService.fetchOrders();
      const d = await mockApi.getDeliveries().catch(() => []);
      const c = await mockApi.getStores().catch(() => []);

      setPedidos(o);
      setRepartidores(d);
      setComercios(c);

      if (o.length > 0) {
        const insight = await getLogisticsInsights(`Pedidos: ${o.length}, Activos: ${d.length}, Región: Posadas`);
        setIaInsight(insight);
      }
    } catch (err) { 
      console.error("Critical Load Error:", err); 
      showToast("Falla de sincronización con el Command Center.", "error");
    } finally { 
      setCargando(false); 
    }
  }, []);

  useEffect(() => { 
    fetchData();
    const interval = setInterval(() => fetchData(true), 5000); // Polling agresivo para demos
    return () => clearInterval(interval);
  }, [fetchData]);

  const handleAssignOrder = async (orderId: number, driverId: number) => {
    try {
      await apiService.assignOrder(orderId, driverId);
      showToast("Socio vinculado a la misión.", "success");
      fetchData(true);
    } catch (err) {
      showToast("Fallo en la asignación remota.", "error");
    }
  };

  const handleUpdateStatus = async (orderId: number, status: EstadoPedido) => {
    try {
      await apiService.updateOrder(orderId, status);
      showToast(`Estado: ${status.replace('_', ' ')}`, "info");
      fetchData(true);
    } catch (err) {
      showToast("Fallo en la actualización de red.", "error");
    }
  };

  if (cargando && pestañaActiva === 'tablero') return (
    <div className="h-screen bg-[#F8FAFC] flex flex-col items-center justify-center">
      <h1 className="text-8xl font-black italic tracking-tighter text-black uppercase animate-pulse">
        Delivery <span className="text-plus-blue">Plus</span>
      </h1>
      <div className="w-64 h-2 bg-slate-200 mt-12 rounded-full overflow-hidden relative">
        <div className="absolute inset-0 bg-plus-blue animate-shimmer"></div>
      </div>
      <p className="mt-8 text-[10px] font-black uppercase tracking-[0.5em] text-slate-400 italic">Estableciendo enlace seguro...</p>
    </div>
  );

  return (
    <Estructura 
      pestañaActiva={pestañaActiva} 
      setPestañaActiva={setPestañaActiva}
      toast={toast}
      onClearToast={() => setToast(null)}
    >
      <MobileSimulator 
        isOpen={isSimulatorOpen} 
        onClose={() => setIsSimulatorOpen(false)} 
        driver={repartidores[0] || {} as SocioRepartidor} 
        activeOrders={pedidos.filter(o => o.estado === EstadoPedido.PENDIENTE || (o.estado === EstadoPedido.ACEPTADO && o.idRepartidor === repartidores[0]?.id))}
        onOrderAccepted={(id) => handleUpdateStatus(id, EstadoPedido.ACEPTADO)}
        onOrderDelivered={(id) => handleUpdateStatus(id, EstadoPedido.ENTREGADO)}
      />

      <button 
        onClick={() => setIsSimulatorOpen(true)}
        className="fixed bottom-10 right-10 z-[150] bg-black text-white px-10 py-6 rounded-[3rem] font-black uppercase text-[10px] tracking-widest shadow-2xl hover:scale-105 transition-all border border-white/10 italic group"
      >
        <span className="group-hover:animate-pulse">📱 Rider Hub</span>
      </button>

      {pestañaActiva === 'tablero' && (
        <div className="space-y-16 animate-in fade-in duration-700">
          <header>
             <p className="text-slate-400 font-black uppercase tracking-[0.4em] text-[10px] italic mb-4">Command Center Hub</p>
             <h2 className="text-[100px] font-black tracking-tighter leading-[0.7] uppercase italic text-black master-text">
               Neural<br/><span className="text-plus-blue">Logistics</span>
             </h2>
          </header>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-10">
            <KPI_Card title="Red Liquidez" value={`$${(pedidos.reduce((acc, p) => acc + p.monto, 0) / 1000).toFixed(1)}k`} icon="💰" color="bg-black" textColor="text-white" />
            <KPI_Card title="Nodos Activos" value={pedidos.length} icon="🏬" color="bg-white" />
            <KPI_Card title="SLA Global" value="99.9%" icon="⚡" color="bg-white" />
            <KPI_Card title="Latitud Server" value="12ms" icon="📡" color="bg-plus-blue" textColor="text-white" />
          </div>

          <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
            <div className="xl:col-span-8 bg-white rounded-[5rem] border border-black/5 shadow-2xl overflow-hidden h-[700px] organic-card">
               <InteractiveMap center="-27.368,-55.895" stores={comercios} drivers={repartidores} className="w-full h-full" />
            </div>

            <div className="xl:col-span-4 bg-[#0A0A0B] rounded-[5rem] p-12 text-white shadow-2xl flex flex-col border border-white/5 relative overflow-hidden">
               <div className="relative z-10 flex flex-col h-full">
                  <p className="text-[11px] font-black italic uppercase tracking-[0.5em] text-plus-blue mb-8">IA Strategist Audit</p>
                  <div className="flex-1 overflow-y-auto mb-8 space-y-8 no-scrollbar">
                     <div className="p-10 bg-white/5 rounded-[4rem] border-l-8 border-plus-blue italic text-3xl font-black leading-tight tracking-tighter">
                       "{iaInsight}"
                     </div>
                     <div className="space-y-4 px-4">
                        <p className="text-[10px] font-black uppercase text-white/20 tracking-widest leading-relaxed">
                          Monitor de Sistema:
                        </p>
                        <ul className="text-xs font-bold italic text-white/60 space-y-2">
                          <li className="flex items-center gap-2"><span className="w-1.5 h-1.5 rounded-full bg-emerald-500"></span> VPS Online: Garupá-01</li>
                          <li className="flex items-center gap-2"><span className="w-1.5 h-1.5 rounded-full bg-blue-500"></span> Mercado Pago: SDK v2 Loaded</li>
                        </ul>
                     </div>
                  </div>
                  <button onClick={() => fetchData()} className="w-full bg-white text-black py-7 rounded-[2.5rem] font-black uppercase text-[10px] tracking-widest italic hover:bg-plus-blue hover:text-white transition-all shadow-2xl">Refrescar Red</button>
               </div>
               <div className="absolute -bottom-10 -right-10 text-[15rem] font-black text-white/[0.02] italic rotate-12 pointer-events-none">IA</div>
            </div>
          </div>
        </div>
      )}

      {pestañaActiva === 'ventas' && <SeccionVentasView activeOrders={pedidos.filter(o => o.estado !== EstadoPedido.ENTREGADO)} />}
      {pestañaActiva === 'gestion' && (
        <OrderManagementView 
          pedidos={pedidos} 
          repartidores={repartidores} 
          onAssign={handleAssignOrder} 
          onUpdateStatus={handleUpdateStatus} 
        />
      )}
      {pestañaActiva === 'alta-comercio' && <StoreOnboardingView />}
      {pestañaActiva === 'socios' && <DriverOnboardingView />}
      {pestañaActiva === 'vercel' && <InfrastructureOpsView />}
      {pestañaActiva === 'billetera' && <WalletView />}
    </Estructura>
  );
};

const KPI_Card = ({ title, value, icon, color, textColor = 'text-black' }: any) => (
  <div className={`${color} p-10 rounded-[4rem] shadow-xl relative overflow-hidden group organic-card border border-black/5 flex flex-col justify-between h-64`}>
    <div className="relative z-10">
      <div className="w-16 h-16 bg-black/5 rounded-[2rem] flex items-center justify-center text-3xl mb-8 group-hover:scale-110 transition-transform">{icon}</div>
      <p className={`text-[9px] font-black uppercase tracking-[0.4em] mb-2 opacity-40 ${textColor}`}>{title}</p>
