import { Pedido, EstadoPedido, SocioRepartidor, Comercio } from '../types';

const API_BASE_URL = ''; 

export const apiService = {
  async fetchOrders(): Promise<Pedido[]> {
    const res = await fetch(`${API_BASE_URL}/api/orders`);
    return await res.json();
  },

  async assignOrder(orderId: number, driverId: number) {
    const res = await fetch(`${API_BASE_URL}/api/orders/${orderId}/assign`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ driverId })
    });
    return await res.json();
  },

  async updateOrder(orderId: number, estado: EstadoPedido) {
    const res = await fetch(`${API_BASE_URL}/api/orders/${orderId}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ estado })
    });
    return await res.json();
  },

  // Nuevos métodos para registro real en backend
  async registerDriver(data: any): Promise<SocioRepartidor> {
    const res = await fetch(`${API_BASE_URL}/api/drivers`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data)
    });
    return await res.json();
  },

  async registerStore(data: any): Promise<Comercio> {
    const res = await fetch(`${API_BASE_URL}/api/stores`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data)
    });
    return await res.json();
  },

  async getDrivers(): Promise<SocioRepartidor[]> {
    const res = await fetch(`${API_BASE_URL}/api/drivers`);
    return await res.json();
  },

  async getStores(): Promise<Comercio[]> {
    const res = await fetch(`${API_BASE_URL}/api/stores`);
    return await res.json();
  },

  async getHealth() {
    const res = await fetch(`${API_BASE_URL}/health`);
    return await res.json();
  }
};

