      </h1>
      <div className="w-64 h-2 bg-slate-200 mt-12 rounded-full overflow-hidden relative">
        <div className="absolute inset-0 bg-plus-blue animate-shimmer"></div>
      </div>
    </div>
  );

  return (
    <Estructura 
      pestañaActiva={pestañaActiva} 
      setPestañaActiva={setPestañaActiva}
      toast={toast}
      onClearToast={() => setToast(null)}
    >
      <MobileSimulator 
        isOpen={isSimulatorOpen} 
        onClose={() => setIsSimulatorOpen(false)} 
        driver={repartidores[0] || {} as SocioRepartidor} 
        activeOrders={pedidos.filter(o => o.estado === EstadoPedido.PENDIENTE || (o.estado === EstadoPedido.ACEPTADO && o.idRepartidor === repartidores[0]?.id))}
        onOrderAccepted={(id) => handleUpdateStatus(id, EstadoPedido.ACEPTADO)}
        onOrderDelivered={(id) => handleUpdateStatus(id, EstadoPedido.ENTREGADO)}
      />

      <button onClick={() => setIsSimulatorOpen(true)} className="fixed bottom-10 right-10 z-[150] bg-black text-white px-10 py-6 rounded-full font-black uppercase text-[10px] tracking-widest shadow-2xl hover:scale-105 transition-all border border-white/10 italic">📱 Rider Hub</button>

      {pestañaActiva === 'tablero' && (
        <div className="space-y-16 animate-in fade-in duration-700">
          <header className="flex flex-col md:flex-row justify-between items-end gap-10">
             <div>
               <p className="text-slate-400 font-black uppercase tracking-[0.4em] text-[10px] italic mb-4">Command Console Live</p>
               <h2 className="text-[110px] font-black tracking-tighter leading-[0.7] uppercase italic text-black">
                 Neural<br/><span className="text-plus-blue">Dashboard</span>
               </h2>
             </div>
             <div className="bg-emerald-50 border border-emerald-100 px-10 py-6 rounded-[3rem] text-emerald-600 font-black uppercase text-[10px] tracking-widest flex items-center gap-4">
               <span className="w-3 h-3 bg-emerald-500 rounded-full animate-pulse"></span> Sistema Online • {apiService.getEnv()}
             </div>
          </header>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-10">
            <KPI_Card title="Volumen Red" value={`$${(pedidos.reduce((acc, p) => acc + p.monto, 0) / 1000).toFixed(1)}k`} icon="💰" color="bg-black" textColor="text-white" />
            <KPI_Card title="Nodos Activos" value={comercios.length} icon="🏬" color="bg-white" />
            <KPI_Card title="Efectividad" value="99.9%" icon="⚡" color="bg-white" />
            <KPI_Card title="Socios Conectados" value={repartidores.length} icon="🛵" color="bg-plus-blue" textColor="text-white" />
          </div>

          <div className="grid grid-cols-1 xl:grid-cols-12 gap-10">
            <div className="xl:col-span-8 bg-white rounded-[5rem] border border-black/5 shadow-2xl overflow-hidden h-[700px] organic-card">
               <InteractiveMap center="-27.368,-55.895" stores={comercios} drivers={repartidores} className="w-full h-full" />
            </div>

            <div className="xl:col-span-4 bg-[#0A0A0B] rounded-[5rem] p-12 text-white shadow-2xl flex flex-col border border-white/5 overflow-hidden">
               <p className="text-[11px] font-black italic uppercase tracking-[0.5em] text-plus-blue mb-8">IA Analyst Report</p>
               <div className="flex-1 overflow-y-auto mb-8 space-y-8 no-scrollbar">
                  <div className="p-10 bg-white/5 rounded-[4rem] border-l-8 border-plus-blue italic text-3xl font-black leading-tight tracking-tighter">
                    "{iaInsight}"
                  </div>
                  <div className="bg-white/5 p-8 rounded-[3rem] border border-white/5">
                     <p className="text-[8px] font-black text-white/30 uppercase tracking-widest mb-4">Traffic Audit:</p>
                     <div className="space-y-3">
                        <div className="flex justify-between items-center text-[10px] font-bold italic">
                           <span>Posadas Centro</span>
                           <span className="text-emerald-400">Fluido</span>
                        </div>
                        <div className="flex justify-between items-center text-[10px] font-bold italic">
                           <span>Garupá Nodo</span>
                           <span className="text-amber-400">Demanda Alta</span>
                        </div>
                     </div>
                  </div>
               </div>
               <button onClick={() => fetchData()} className="w-full bg-white text-black py-7 rounded-full font-black uppercase text-[10px] tracking-widest italic hover:bg-plus-blue hover:text-white transition-all">Sincronizar Nodo</button>
            </div>
          </div>
        </div>
      )}

      {pestañaActiva === 'ventas' && <SeccionVentasView activeOrders={pedidos.filter(o => o.estado !== EstadoPedido.ENTREGADO)} />}
      {pestañaActiva === 'gestion' && (
        <OrderManagementView 
          pedidos={pedidos} 
          repartidores={repartidores} 
          onAssign={handleAssignOrder} 
          onUpdateStatus={handleUpdateStatus} 
        />
      )}
      {pestañaActiva === 'alta-comercio' && <StoreOnboardingView />}
      {pestañaActiva === 'socios' && <DriverOnboardingView />}
      {pestañaActiva === 'vercel' && <InfrastructureOpsView />}
      {pestañaActiva === 'billetera' && <WalletView />}
    </Estructura>
  );
};

const KPI_Card = ({ title, value, icon, color, textColor = 'text-black' }: any) => (
