import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';

const VoiceCommandCenter: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [transcription, setTranscription] = useState('');
  const [status, setStatus] = useState<'IDLE' | 'CONNECTING' | 'LISTENING' | 'SPEAKING' | 'ERROR_QUOTA'>('IDLE');

  const audioContextInRef = useRef<AudioContext | null>(null);
  const audioContextOutRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const outputNodeRef = useRef<GainNode | null>(null);
  const sessionRef = useRef<any>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  function encode(bytes: Uint8Array) {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) binary += String.fromCharCode(bytes[i]);
    return btoa(binary);
  }

  function decode(base64: string) {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
    return bytes;
  }

  async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  }

  const handleOpenKeySelector = async () => {
    if (window.aistudio?.openSelectKey) {
      await window.aistudio.openSelectKey();
      setStatus('IDLE');
    }
  };

  const startSession = async () => {
    if (isActive) return;
    setStatus('CONNECTING');
    setIsActive(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const systemInstruction = `
        Rol: Sos el Coordinador Logístico Senior de Delivery Plus.
        Cliente: Hablás con dueños de comercios (farmacias, ferreterías, ropa, gastronomía).
        Objetivo: Vender turnos de delivery, packs de envíos o cerrar contratos.

        Oferta:
        1. Moto Express: 30min ($5000).
        2. Camioneta Cargo: Bultos grandes ($15000).
        3. Plan Business: 50 envíos con 20% OFF.

        Tono: Profesional, resolutivo. Breve.
      `;

      audioContextInRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextOutRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      outputNodeRef.current = audioContextOutRef.current.createGain();
      outputNodeRef.current.connect(audioContextOutRef.current.destination);

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStatus('LISTENING');
            const source = audioContextInRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextInRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextInRef.current!.destination);
            sessionRef.current = { stopMic: () => { 
              source.disconnect(); 
              scriptProcessor.disconnect(); 
              stream.getTracks().forEach(t => t.stop());
            }};
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.outputTranscription) {
              setTranscription(prev => prev + ' ' + message.serverContent?.outputTranscription?.text);
            }
            const audioBase64 = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioBase64) {
              setStatus('SPEAKING');
              const ctx = audioContextOutRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audioBase64), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputNodeRef.current!);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setStatus('LISTENING');
              };
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }
          },
          onerror: (e: any) => {
            console.error("Live Error:", e);
            if (e.message?.includes('429') || e.message?.includes('quota')) {
              setStatus('ERROR_QUOTA');
            }
            stopSession();
          },
          onclose: () => stopSession()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
          systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {}
        }
      });
    } catch (err: any) {
      if (err.message?.includes('429')) setStatus('ERROR_QUOTA');
      stopSession();
    }
  };

  const stopSession = () => {
    setIsActive(false);
    if (status !== 'ERROR_QUOTA') setStatus('IDLE');
    if (sessionRef.current) sessionRef.current.stopMic();
    if (audioContextInRef.current) audioContextInRef.current.close();
    if (audioContextOutRef.current) audioContextOutRef.current.close();
    sourcesRef.current.forEach(s => s.stop());
    sourcesRef.current.clear();
  };

  return (
    <div className="space-y-12 animate-in fade-in duration-700 h-[calc(100vh-180px)] flex flex-col">
      <header className="bg-white p-14 rounded-[5rem] shadow-sm border border-slate-100 flex justify-between items-center">
        <div>
          <h2 className="text-7xl font-black tracking-tighter italic uppercase leading-none text-black">Voice <span className="text-plus-blue">Command</span></h2>
          <p className="text-slate-400 mt-6 text-2xl font-medium italic">Terminal de ventas neuronal via Gemini Live</p>
        </div>
        <div className="flex gap-4">
           {status === 'ERROR_QUOTA' ? (
             <button 
               onClick={handleOpenKeySelector}
               className="bg-red-50 text-red-600 px-8 py-4 rounded-full font-black text-[10px] uppercase tracking-widest border border-red-100 animate-pulse"
             >
                ⚠️ Cuota Excedida - Cambiar API Key
             </button>
           ) : (
             <div className={`px-8 py-4 rounded-full font-black text-[10px] uppercase tracking-widest border transition-all ${isActive ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-slate-50 text-slate-400 border-slate-100'}`}>
                Status: {status}
             </div>
           )}
        </div>
      </header>

      <div className="flex-1 grid grid-cols-1 lg:grid-cols-2 gap-12 overflow-hidden">
        <div className="bg-[#0A0A0B] rounded-[6rem] p-16 text-white shadow-3xl relative overflow-hidden flex flex-col justify-center items-center">
           <div className="relative z-10 flex flex-col items-center gap-16">
              <div className="relative">
                 <div className={`w-64 h-64 rounded-full flex items-center justify-center transition-all duration-500 z-10 relative ${isActive ? 'bg-plus-blue shadow-[0_0_100px_rgba(37,99,235,0.6)]' : 'bg-white/5 border border-white/10'}`}>
                    <span className="text-7xl">{isActive ? '🎙️' : (status === 'ERROR_QUOTA' ? '🚫' : '🔘')}</span>
                 </div>
                 {isActive && (
                   <>
                    <div className="absolute inset-0 bg-plus-blue rounded-full animate-ping opacity-20"></div>
                    <div className="absolute -inset-8 border border-plus-blue/20 rounded-full animate-pulse"></div>
                   </>
                 )}
              </div>

              <div className="text-center space-y-6">
                 {status === 'ERROR_QUOTA' ? (
                   <>
                     <h4 className="text-4xl font-black italic uppercase tracking-tighter text-red-500">LIMITE ALCANZADO</h4>
                     <p className="text-white/40 text-[10px] font-black uppercase tracking-[0.5em]">Por favor, usa tu propia llave con facturación.</p>
                   </>
                 ) : (
                   <>
                     <h4 className="text-4xl font-black italic uppercase tracking-tighter">
                       {isActive ? (status === 'SPEAKING' ? 'IA RESPONDIENDO...' : 'ESCUCHANDO...') : 'TERMINAL EN REPOSO'}
                     </h4>
                     <p className="text-white/40 text-[10px] font-black uppercase tracking-[0.5em]">Vínculo Neural Delivery Plus v2.5</p>
                   </>
                 )}
              </div>

              <div className="flex flex-col gap-4 w-full">
                <button 
                  onClick={isActive ? stopSession : startSession}
                  className={`px-16 py-8 rounded-full font-black uppercase tracking-[0.3em] text-sm shadow-2xl transition-all hover:scale-105 active:scale-95 ${isActive ? 'bg-red-600 text-white' : 'bg-white text-black'}`}
                >
                  {isActive ? 'FINALIZAR ENLACE' : 'INICIAR LLAMADA'}
                </button>
                {status === 'ERROR_QUOTA' && (
                  <button onClick={handleOpenKeySelector} className="text-xs text-plus-blue font-black uppercase tracking-widest hover:underline">
                    Configurar API Key Personal
                  </button>
                )}
              </div>
           </div>
           <div className="absolute bottom-12 flex gap-1 items-end h-20 opacity-10">
              {[...Array(40)].map((_, i) => (
                <div key={i} className="w-1 bg-white rounded-full" style={{ height: isActive ? `${20 + Math.random() * 80}%` : '5%', transition: 'height 0.1s' }}></div>
              ))}
           </div>
        </div>

        <div className="bg-white rounded-[6rem] border border-slate-100 shadow-sm p-16 flex flex-col overflow-hidden">
           <div className="flex items-center gap-4 mb-10">
              <div className="w-10 h-10 bg-slate-100 rounded-full flex items-center justify-center text-xl">📜</div>
              <h4 className="text-[10px] font-black uppercase tracking-widest text-slate-400">Negotiation Transcript</h4>
           </div>

           <div className="flex-1 bg-slate-50 rounded-[4rem] p-12 overflow-y-auto no-scrollbar border border-slate-100 italic font-medium text-2xl text-slate-800 leading-relaxed">
              {transcription || "Inicia la llamada para negociar turnos logísticos..."}
           </div>
        </div>
      </div>
    </div>
  );
};

