import React, { useState, useEffect } from 'react';

interface ToastProps {
  message: string;
  type: 'error' | 'success' | 'info';
  onClose: () => void;
}

const Toast: React.FC<ToastProps> = ({ message, type, onClose }) => {
  useEffect(() => {
    const timer = setTimeout(onClose, 5000);
    return () => clearTimeout(timer);
  }, [onClose]);

  const bg = type === 'error' ? 'bg-red-600' : type === 'success' ? 'bg-emerald-600' : 'bg-plus-blue';

  return (
    <div className={`fixed top-10 right-10 z-[300] ${bg} text-white px-8 py-5 rounded-[2rem] shadow-2xl animate-in slide-in-from-right duration-500 flex items-center gap-4 border border-white/10`}>
      <span className="text-xl">{type === 'error' ? '🚫' : type === 'success' ? '✅' : 'ℹ️'}</span>
      <p className="text-[10px] font-black uppercase tracking-widest">{message}</p>
    </div>
  );
};

