import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';

const VoiceCommandCenter: React.FC = () => {
  const [isActive, setIsActive] = useState(false);
  const [transcription, setTranscription] = useState('');
  const [status, setStatus] = useState<'IDLE' | 'CONNECTING' | 'LISTENING' | 'SPEAKING' | 'ERROR_QUOTA'>('IDLE');

  const audioContextInRef = useRef<AudioContext | null>(null);
  const audioContextOutRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const outputNodeRef = useRef<GainNode | null>(null);
  const sessionRef = useRef<any>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Utilería de Audio
  function encode(bytes: Uint8Array) {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) binary += String.fromCharCode(bytes[i]);
    return btoa(binary);
  }

  function decode(base64: string) {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
    return bytes;
  }

  async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
    for (let channel = 0; channel < numChannels; channel++) {
      const channelData = buffer.getChannelData(channel);
      for (let i = 0; i < frameCount; i++) {
        channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
      }
    }
    return buffer;
  }

  const handleOpenKeySelector = async () => {
    if (window.aistudio?.openSelectKey) {
      await window.aistudio.openSelectKey();
      setStatus('IDLE');
    }
  };

  const startSession = async () => {
    if (isActive) return;
    setStatus('CONNECTING');
    setIsActive(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const systemInstruction = `
        Rol: Sos el Coordinador Logístico Senior de Delivery Plus.
        Cliente: Estás hablando con dueños de comercios (farmacias, ferreterías, repuestos, gastronomía).
        Objetivo: Vender turnos de delivery o cerrar contratos de envíos.
        Contexto: Vendemos logística de precisión, no comida. Lo importante es rapidez, seguridad y precio.

        Reglas de Negocio:
        1. Si piden flete/moto, preguntá: "¿Qué mercadería es? ¿Entra en mochila o caja?".
        2. Ofrecé packs: "Si contratás 10 envíos semanales te hago precio de flota".
        3. Tono: Profesional, ejecutivo, resolutivo.

        Tarifas sugeridas: Moto Express $5000, Camioneta $15000.
      `;

      audioContextInRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      audioContextOutRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      outputNodeRef.current = audioContextOutRef.current.createGain();
      outputNodeRef.current.connect(audioContextOutRef.current.destination);

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStatus('LISTENING');
            const source = audioContextInRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextInRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextInRef.current!.destination);
            sessionRef.current = { stopMic: () => { 
              source.disconnect(); 
              scriptProcessor.disconnect(); 
              stream.getTracks().forEach(t => t.stop());
            }};
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.outputTranscription) {
              setTranscription(prev => prev + ' ' + message.serverContent?.outputTranscription?.text);
            }
            if (message.serverContent?.inputTranscription) {
               // Opcional: mostrar lo que el usuario está diciendo
            }

            const audioBase64 = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioBase64) {
              setStatus('SPEAKING');
              const ctx = audioContextOutRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audioBase64), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputNodeRef.current!);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setStatus('LISTENING');
              };
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }
          },
          onerror: (e: any) => {
            console.error("Live Error:", e);
            if (e.message?.includes('429')) setStatus('ERROR_QUOTA');
            stopSession();
          },
          onclose: () => stopSession()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
          systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {}
        }
      });
    } catch (err: any) {
      if (err.message?.includes('429')) setStatus('ERROR_QUOTA');
      stopSession();
    }
  };

  const stopSession = () => {
    setIsActive(false);
    if (status !== 'ERROR_QUOTA') setStatus('IDLE');
    if (sessionRef.current) sessionRef.current.stopMic();
    if (audioContextInRef.current) audioContextInRef.current.close();
    if (audioContextOutRef.current) audioContextOutRef.current.close();
    sourcesRef.current.forEach(s => s.stop());
    sourcesRef.current.clear();
  };

  return (
    <div className="space-y-12 animate-in fade-in duration-700 h-[calc(100vh-180px)] flex flex-col">
      <header className="bg-white p-14 rounded-[4rem] shadow-sm border border-slate-100 flex flex-col md:flex-row justify-between items-center gap-6">
        <div>
          <h2 className="text-7xl font-black tracking-tighter italic uppercase leading-none text-black">Walkie <span className="text-plus-blue">Talkie</span></h2>
          <p className="text-slate-400 mt-4 text-xl font-medium italic uppercase tracking-widest">Negociador de Logística Neural v2.5</p>
        </div>

        {status === 'ERROR_QUOTA' ? (
          <button onClick={handleOpenKeySelector} className="bg-red-50 text-red-600 px-10 py-5 rounded-full font-black text-xs uppercase tracking-widest border border-red-100 animate-pulse">
            ⚠️ Cuota Excedida - Cambiar Key
          </button>
        ) : (
          <div className={`px-10 py-5 rounded-full font-black text-xs uppercase tracking-widest border transition-all flex items-center gap-3 ${isActive ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-slate-50 text-slate-400 border-slate-100'}`}>
             <span className={`w-3 h-3 rounded-full ${isActive ? 'bg-emerald-500 animate-pulse' : 'bg-slate-300'}`}></span>
             {status}
          </div>
        )}
      </header>

      <div className="flex-1 grid grid-cols-1 lg:grid-cols-2 gap-12 overflow-hidden">
        {/* Consola de Audio */}
        <div className="bg-[#050505] rounded-[5rem] p-16 text-white shadow-3xl relative overflow-hidden flex flex-col justify-center items-center">
           <div className="absolute inset-0 opacity-10 pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')]"></div>

           <div className="relative z-10 flex flex-col items-center gap-16">
              <div className="relative">
                 <button 
                  onMouseDown={startSession}
                  onMouseUp={stopSession}
                  onTouchStart={startSession}
                  onTouchEnd={stopSession}
                  className={`w-64 h-64 rounded-full flex items-center justify-center transition-all duration-300 z-10 relative shadow-[0_0_60px_rgba(0,0,0,0.5)] active:scale-90 ${isActive ? 'bg-plus-blue shadow-[0_0_100px_rgba(37,99,235,0.6)]' : 'bg-white/5 border-4 border-white/10 hover:border-plus-blue/50'}`}
                 >
                    <span className="text-7xl">{isActive ? '🎙️' : '📞'}</span>
                 </button>
                 {isActive && <div className="absolute -inset-10 bg-plus-blue rounded-full animate-ping opacity-20"></div>}
              </div>

              <div className="text-center space-y-4">
                 <h4 className="text-4xl font-black italic uppercase tracking-tighter">
                   {isActive ? (status === 'SPEAKING' ? 'IA RESPONDIENDO...' : 'MANTENÉ PARA HABLAR') : 'TERMINAL DISPONIBLE'}
                 </h4>
                 <p className="text-white/40 text-[10px] font-black uppercase tracking-[0.5em]">Sistema de Enlace de Voz Directo</p>
              </div>
           </div>

           {/* Waveform Fake */}
           <div className="absolute bottom-16 flex gap-1.5 items-end h-24 opacity-20">
              {[...Array(50)].map((_, i) => (
                <div 
                  key={i} 
                  className="w-1.5 bg-plus-blue rounded-full" 
                  style={{ 
                    height: isActive ? `${20 + Math.random() * 80}%` : '4px',
                    transition: 'height 0.1s ease-out'
                  }}
                ></div>
              ))}
           </div>
        </div>

        {/* Transcripción */}
        <div className="bg-white rounded-[5rem] border border-slate-100 shadow-xl p-16 flex flex-col overflow-hidden organic-card">
           <div className="flex items-center gap-4 mb-10 border-b border-slate-50 pb-8">
              <div className="w-12 h-12 bg-slate-900 rounded-2xl flex items-center justify-center text-2xl">📜</div>
              <div>
                <h4 className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-400">Minuta de Negociación</h4>
                <p className="text-lg font-black italic uppercase">Live Transcript</p>
              </div>
           </div>

           <div className="flex-1 bg-slate-50 rounded-[3rem] p-12 overflow-y-auto no-scrollbar italic font-medium text-3xl text-slate-800 leading-tight tracking-tight">
              {transcription || "Esperando conexión para transcribir la negociación..."}
           </div>

           <div className="mt-10 p-10 bg-plus-blue rounded-[3rem] text-white flex justify-between items-center shadow-2xl">
              <div>
                 <p className="text-[9px] font-black uppercase opacity-60 mb-2 tracking-widest leading-none">Insight Estratégico IA</p>
                 <p className="text-xl font-black italic tracking-tighter leading-tight">"El cliente necesita urgencia. Ofrecé el Seguro de Carga Plus."</p>
              </div>
              <div className="text-5xl opacity-30">⚡</div>
           </div>
        </div>
      </div>
    </div>
  );
};

export default VoiceCommandCenter;

import React, { useState, useEffect, useCallback } from 'react';
import Estructura from './components/Layout';
import MobileSimulator from './components/MobileSimulator';
import OrderManagementView from './components/OrderManagementView';
import VoiceCommandCenter from './components/VoiceCommandCenter';
import StoreOnboardingView from './components/StoreOnboardingView';
import DriverOnboardingView from './components/DriverOnboardingView';
import DriverReputationView from './components/DriverReputationView';
import WalletView from './components/WalletView';
import InfrastructureOpsView from './components/VercelOpsView';
import { apiService } from './services/apiService';
import { Pedido, EstadoPedido, SocioRepartidor, Comercio } from './types';

const App: React.FC = () => {
  const [pestañaActiva, setPestañaActiva] = useState('tablero');
  const [pedidos, setPedidos] = useState<Pedido[]>([]);
  const [repartidores, setRepartidores] = useState<SocioRepartidor[]>([]);
  const [comercios, setComercios] = useState<Comercio[]>([]);
  const [cargando, setCargando] = useState(true);
  const [toast, setToast] = useState<{ message: string, type: 'error' | 'success' | 'info' } | null>(null);

  const showToast = (message: string, type: 'error' | 'success' | 'info' = 'info') => {
    setToast({ message, type });
  };

  const fetchData = useCallback(async (isSilent = false) => {
    if (!isSilent) setCargando(true);
    try {
      const [o, d, c] = await Promise.all([
        apiService.fetchOrders(),
        apiService.getDrivers(),
        apiService.getStores()
      ]);
      setPedidos(o);
      setRepartidores(d);
      setComercios(c);
    } catch (err) { 
      console.error(err); 
      showToast("Falla de sincronización de red.", "error");
    } finally { 
      setCargando(false); 
    }
  }, []);

  useEffect(() => { 
    fetchData();
    const interval = setInterval(() => fetchData(true), 10000); 
    return () => clearInterval(interval);
  }, [fetchData]);

  const handleAssignOrder = async (orderId: number, driverId: number) => {
    try {
      await apiService.assignOrder(orderId, driverId);
      showToast("Despliegue de socio iniciado.", "success");
      fetchData(true);
    } catch { showToast("Error en despacho.", "error"); }
  };

  const handleUpdateStatus = async (orderId: number, status: EstadoPedido) => {
    try {
      await apiService.updateOrder(orderId, status);
      showToast(`Evento: ${status}`, "info");
      fetchData(true);
    } catch { showToast("Error de actualización.", "error"); }
  };

  if (cargando && pestañaActiva === 'tablero') return (
    <div className="h-screen bg-black flex flex-col items-center justify-center">
      <h1 className="text-8xl font-black italic text-white uppercase animate-pulse tracking-tighter">Delivery <span className="text-plus-blue">Plus</span></h1>
    </div>
  );

  return (
    <Estructura 
      pestañaActiva={pestañaActiva} 
      setPestañaActiva={setPestañaActiva}
      toast={toast}
      onClearToast={() => setToast(null)}
    >
      {pestañaActiva === 'tablero' && (
        <OrderManagementView 
          pedidos={pedidos} 
          repartidores={repartidores} 
          onAssign={handleAssignOrder} 
          onUpdateStatus={handleUpdateStatus} 
        />
      )}
      {pestañaActiva === 'voice-command' && <VoiceCommandCenter />}
      {pestañaActiva === 'alta-comercio' && <StoreOnboardingView />}
      {pestañaActiva === 'alta-socio' && <DriverOnboardingView />}
      {pestañaActiva === 'reputacion' && <DriverReputationView drivers={repartidores} />}
      {pestañaActiva === 'billetera' && <WalletView />}
      {pestañaActiva === 'vercel' && <InfrastructureOpsView />}
    </Estructura>
  );
};

export default App;

