      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        callbacks: {
          onopen: () => {
            setStatus('LISTENING');
            const source = audioContextInRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = audioContextInRef.current!.createScriptProcessor(4096, 1, 1);
            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) int16[i] = inputData[i] * 32768;
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };
              sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
            };
            source.connect(scriptProcessor);
            scriptProcessor.connect(audioContextInRef.current!.destination);
            sessionRef.current = { stopMic: () => { 
              source.disconnect(); 
              scriptProcessor.disconnect(); 
              stream.getTracks().forEach(t => t.stop());
            }};
          },
          onmessage: async (message: LiveServerMessage) => {
            if (message.serverContent?.outputTranscription) {
              setTranscription(prev => prev + ' ' + message.serverContent?.outputTranscription?.text);
            }

            const audioBase64 = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioBase64) {
              setStatus('SPEAKING');
              const ctx = audioContextOutRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
              const buffer = await decodeAudioData(decode(audioBase64), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(outputNodeRef.current!);
              source.onended = () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setStatus('LISTENING');
              };
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }
          },
          onerror: (e: any) => {
            console.error("Live Error:", e);
            if (e.message?.includes('429')) setStatus('ERROR_QUOTA');
            stopSession();
          },
          onclose: () => stopSession()
        },
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
          systemInstruction,
          inputAudioTranscription: {},
          outputAudioTranscription: {}
        }
      });
    } catch (err: any) {
      if (err.message?.includes('429')) setStatus('ERROR_QUOTA');
      stopSession();
    }
  };

  const stopSession = () => {
    setIsActive(false);
    if (status !== 'ERROR_QUOTA') setStatus('IDLE');
    if (sessionRef.current) sessionRef.current.stopMic();
    if (audioContextInRef.current) audioContextInRef.current.close();
    if (audioContextOutRef.current) audioContextOutRef.current.close();
    sourcesRef.current.forEach(s => s.stop());
    sourcesRef.current.clear();
  };

  return (
    <div className="space-y-12 animate-in fade-in duration-700 h-[calc(100vh-180px)] flex flex-col">
      <header className="bg-white p-14 rounded-[4rem] shadow-sm border border-slate-100 flex flex-col md:flex-row justify-between items-center">
        <div>
          <h2 className="text-7xl font-black tracking-tighter italic uppercase text-black leading-none">Voice <span className="text-plus-blue">CallCenter</span></h2>
          <p className="text-slate-400 mt-4 text-xl font-medium italic">Gemini 2.5 Multimodal Sales Agent</p>
        </div>

        <div className="flex gap-4">
           {status === 'ERROR_QUOTA' && (
             <button onClick={() => window.aistudio.openSelectKey()} className="bg-red-50 text-red-600 px-8 py-4 rounded-full font-black text-[10px] uppercase border border-red-100 animate-pulse">
                Saturación de Red - Cambiar Token
             </button>
           )}
           <div className={`px-10 py-5 rounded-full font-black text-xs uppercase tracking-widest border transition-all ${isActive ? 'bg-emerald-50 text-emerald-600 border-emerald-100' : 'bg-slate-50 text-slate-400 border-slate-100'}`}>
              Status: {status}
           </div>
        </div>
      </header>

      <div className="flex-1 grid grid-cols-1 lg:grid-cols-2 gap-12 overflow-hidden">
        <div className="bg-[#050505] rounded-[5rem] p-16 text-white shadow-3xl relative overflow-hidden flex flex-col justify-center items-center">
           <div className="absolute inset-0 opacity-20 pointer-events-none bg-[radial-gradient(circle_at_center,_var(--plus-blue)_0%,_transparent_70%)]"></div>

           <div className="relative z-10 flex flex-col items-center gap-16">
              <div className="relative">
                 <button 
                  onMouseDown={startSession}
                  onMouseUp={stopSession}
                  className={`w-64 h-64 rounded-full flex items-center justify-center transition-all duration-300 z-10 relative active:scale-90 shadow-2xl ${isActive ? 'bg-plus-blue shadow-[0_0_100px_rgba(37,99,235,0.6)]' : 'bg-white/5 border border-white/10 hover:border-plus-blue/50'}`}
                 >
                    <span className="text-7xl">{isActive ? '🎙️' : '🔘'}</span>
                 </button>
                 {isActive && <div className="absolute -inset-10 bg-plus-blue rounded-full animate-ping opacity-20"></div>}
              </div>

              <div className="text-center space-y-4">
                 <h4 className="text-4xl font-black italic uppercase tracking-tighter">
                   {isActive ? (status === 'SPEAKING' ? 'IA NEGOCIANDO...' : 'MANTENÉ PARA HABLAR') : 'TERMINAL DISPONIBLE'}
                 </h4>
                 <p className="text-white/40 text-[10px] font-black uppercase tracking-[0.5em]">Human-AI Hybrid Sales Interface</p>
              </div>
           </div>
