        <OrderManagementView 
          pedidos={pedidos} 
          repartidores={repartidores} 
          onAssign={(oid, did) => apiService.assignOrder(oid, did).then(() => fetchData(true))} 
          onUpdateStatus={(oid, status) => apiService.updateOrder(oid, status).then(() => fetchData(true))} 
        />
      )}
      {pestañaActiva === 'voice-command' && <VoiceCommandCenter />}
      {pestañaActiva === 'hybrid-support' && <HybridSupportView />}
      {pestañaActiva === 'alta-socio' && <DriverOnboardingView />}
      {pestañaActiva === 'billetera' && <WalletView />}
      {pestañaActiva === 'vercel' && <InfrastructureOpsView />}
