import { Pedido, EstadoPedido, SocioRepartidor, Comercio, WeatherNow } from '../types';

const API_BASE_URL = process.env.API_BASE_URL || 'http://localhost:5050'; 

export const apiService = {
  getEnv() {
    return window.location.hostname === 'localhost' ? "DEV_NET8_LOCAL" : "PROD_CENTRAL_CORE";
  },

  async fetchOrders(): Promise<Pedido[]> {
    try {
      const res = await fetch(`${API_BASE_URL}/api/v1/orders`);
      if (!res.ok) throw new Error('Error de red');
      return await res.json();
    } catch {
      const { mockApi } = await import('./mockApi');
      const orders = await mockApi.getOrders();
      // Mapeo simple de estados para compatibilidad con el mock
      return orders.map(o => ({
        ...o,
        storefrontSlug: 'default',
        platformFee: o.monto * 0.2,
        driverNet: o.monto * 0.8,
        deliveryLat: o.latitud,
        deliveryLng: o.longitud,
        deliveryAddressText: 'Dirección Mock',
        estado: o.estado as unknown as EstadoPedido
      })) as unknown as Pedido[];
    }
  },

  async assignOrder(orderId: number | string, driverId: number | string) {
    const res = await fetch(`${API_BASE_URL}/api/v1/orders/${orderId}/assign?driverId=${driverId}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' }
    });
    return await res.json();
  },

  async updateOrder(orderId: number | string, status: EstadoPedido) {
    // En .NET usamos rutas específicas según el flujo
    let endpoint = `${API_BASE_URL}/api/v1/orders/${orderId}`;
    if (status === EstadoPedido.READY_FOR_PICKUP) endpoint += '/ready';
    if (status === EstadoPedido.PICKED_UP) endpoint += '/pickup';
    if (status === EstadoPedido.DELIVERED) endpoint += '/deliver';

    const res = await fetch(endpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' }
    });
    return await res.json();
  },

  async fetchWeather(lat: number, lng: number): Promise<WeatherNow> {
    try {
      const res = await fetch(`${API_BASE_URL}/api/v1/weather/now?lat=${lat}&lng=${lng}`);
      return await res.json();
    } catch {
      return { temp: 22, rainProb: 10, wind: 5, summary: 'Despejado' };
    }
  },

  async registerDriver(data: any): Promise<SocioRepartidor> {
    const res = await fetch(`${API_BASE_URL}/api/v1/notifications/token`, { // Placeholder real
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data)
    });
    return await res.json();
  },

  async registerStore(data: any): Promise<Comercio> {
    const res = await fetch(`${API_BASE_URL}/api/v1/stores`, { // Ajustado a la estructura .NET
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data)
    });
    return await res.json();
  },

  async getDrivers(): Promise<SocioRepartidor[]> {
    try {
      const res = await fetch(`${API_BASE_URL}/api/v1/drivers`);
      return await res.json();
    } catch {
      const { mockApi } = await import('./mockApi');
      return mockApi.getDeliveries();
    }
  },

  async getStores(): Promise<Comercio[]> {
    try {
      const res = await fetch(`${API_BASE_URL}/api/v1/stores`);
      return await res.json();
    } catch {
      const { mockApi } = await import('./mockApi');
      return mockApi.getStores();
    }
  }
};

