import { Pedido, EstadoPedido, SocioRepartidor, Comercio, WeatherNow } from '../types';

const API_BASE_URL = process.env.API_BASE_URL || 'http://localhost:5050'; 

export const apiService = {
  getEnv() {
    return window.location.hostname === 'localhost' ? "TRANSFORME_LOCAL_DEV" : "TRANSFORME_PRODUCTION_CORE";
  },

  async fetchOrders(): Promise<Pedido[]> {
    try {
      const res = await fetch(`${API_BASE_URL}/api/v1/orders`);
      if (!res.ok) throw new Error('Backend Offline');
      const data = await res.json();
      // Adaptación de datos .NET a UI Frontend
      return data.map((o: any) => ({
        ...o,
        monto: o.total,
        idRepartidor: o.driverId,
        creadoEn: o.createdAt,
        // Fallbacks para UI que requiere nombre de cliente (mientras se integra auth real)
        nombreCliente: o.nombreCliente || `Cliente #${o.id.slice(0,4)}`,
        detalles: o.items?.map((i: any) => `${i.qty}x Producto`).join(', ') || "Pedido General"
      }));
    } catch {
      const { mockApi } = await import('./mockApi');
      const mockOrders = await mockApi.getOrders();
      return mockOrders as unknown as Pedido[];
    }
  },

  async assignOrder(orderId: string | number, driverId: string | number) {
    const res = await fetch(`${API_BASE_URL}/api/v1/orders/${orderId}/assign?driverId=${driverId}`, {
      method: 'POST'
    });
    return await res.json();
  },

  async updateOrder(orderId: string | number, status: EstadoPedido) {
    let endpoint = `${API_BASE_URL}/api/v1/orders/${orderId}`;
    if (status === EstadoPedido.READY_FOR_PICKUP) endpoint += '/ready';
    else if (status === EstadoPedido.PICKED_UP) endpoint += '/pickup';
    else if (status === EstadoPedido.DELIVERED) endpoint += '/deliver';
    else return { error: "Flujo no soportado por API v1" };

    const res = await fetch(endpoint, { method: 'POST' });
    return await res.json();
  },

  async fetchWeather(lat: number, lng: number): Promise<WeatherNow> {
    try {
      const res = await fetch(`${API_BASE_URL}/api/v1/weather/now?lat=${lat}&lng=${lng}`);
      if (!res.ok) throw new Error();
      return await res.json();
    } catch {
      return { temp: 22, rainProb: 15, wind: 10, summary: "Parcialmente nublado" };
    }
  },

  async getDrivers(): Promise<SocioRepartidor[]> {
    try {
      const res = await fetch(`${API_BASE_URL}/api/v1/drivers`);
      return await res.json();
    } catch {
      const { mockApi } = await import('./mockApi');
      return mockApi.getDeliveries() as unknown as SocioRepartidor[];
    }
  },

  async getStores(): Promise<Comercio[]> {
    try {
      const res = await fetch(`${API_BASE_URL}/api/v1/stores`);
      return await res.json();
    } catch {
      const { mockApi } = await import('./mockApi');
      return mockApi.getStores() as unknown as Comercio[];
    }
  },

  async registerDriver(data: any) {
    const res = await fetch(`${API_BASE_URL}/api/v1/notifications/token`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data)
    });
    return await res.json();
  }
};

