      setPestañaActiva={setPestañaActiva}
      toast={toast}
      onClearToast={() => setToast(null)}
    >
      {pestañaActiva === 'tablero' && (
        <OrderManagementView 
          pedidos={pedidos} 
          repartidores={repartidores} 
          onAssign={(oid, did) => apiService.assignOrder(String(oid), String(did)).then(() => fetchData(true))} 
          onUpdateStatus={(oid, status) => apiService.updateOrder(String(oid), status).then(() => fetchData(true))} 
        />
