        <div>
          <h2 className="text-7xl font-black tracking-tighter italic uppercase text-black leading-none">
            Command <span className="text-plus-blue">Center</span>
          </h2>
          <p className="text-slate-400 mt-4 text-xl font-medium italic">Orquestación de flujos logísticos y despacho neural</p>
        </div>

        <div className="flex bg-slate-100 p-2 rounded-[2.5rem] border border-black/5 overflow-x-auto no-scrollbar">
           {['ALL', 'PENDIENTE', 'ACEPTADO', 'EN_CAMINO', 'ENTREGADO'].map(status => (
             <button 
               key={status}
               onClick={() => setFilter(status as any)}
               className={`px-6 py-3 rounded-[2rem] text-[9px] font-black uppercase tracking-widest transition-all whitespace-nowrap ${filter === status ? 'bg-black text-white shadow-xl' : 'text-black/30 hover:text-black'}`}
             >
               {status}
             </button>
           ))}
        </div>
      </header>

      <div className="grid grid-cols-1 xl:grid-cols-12 gap-10 min-h-[800px]">
        {/* Listado Principal */}
        <div className="xl:col-span-4 bg-white p-10 rounded-[5rem] border border-black/5 shadow-2xl flex flex-col overflow-hidden organic-card">
          <div className="flex-1 overflow-y-auto pr-4 space-y-6 no-scrollbar">
            {filteredOrders.map(order => (
              <div 
                key={order.id}
                onClick={() => setSelectedId(order.id)}
                className={`p-10 rounded-[3.5rem] border transition-all cursor-pointer relative overflow-hidden group ${selectedId === order.id ? 'bg-black text-white border-black shadow-2xl scale-[1.01]' : 'bg-slate-50 border-black/5 hover:border-plus-blue/30'}`}
              >
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <span className={`text-[8px] font-black uppercase tracking-[0.3em] ${selectedId === order.id ? 'text-plus-blue' : 'text-slate-400'}`}>#{String(order.id).slice(0,5)}</span>
                    <h4 className="text-2xl font-black italic uppercase tracking-tighter mt-1">{order.nombreCliente}</h4>
                  </div>
                  <StatusBadge status={order.estado} />
                </div>
                <p className={`text-sm font-bold italic truncate ${selectedId === order.id ? 'text-white/60' : 'text-black/40'}`}>{order.detalles}</p>
                <div className="mt-8 flex justify-between items-center">
                   <p className="text-2xl font-black italic tracking-tighter">${order.monto.toLocaleString()}</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Mapa Interactivo */}
        <div className="xl:col-span-5 bg-white rounded-[5rem] overflow-hidden border border-black/5 shadow-2xl relative">
            <InteractiveMap 
              center="-27.368,-55.895"
              stores={[]}
              drivers={repartidores}
              className="w-full h-full"
              pickup={selectedOrder ? { lat: selectedOrder.latitud, lng: selectedOrder.longitud } : undefined}
              delivery={selectedOrder ? { lat: selectedOrder.latUsuario, lng: selectedOrder.lngUsuario } : undefined}
            />
        </div>

        {/* Panel de Control */}
        <div className="xl:col-span-3 bg-[#0A0A0B] text-white p-12 rounded-[5rem] shadow-3xl flex flex-col border border-white/5 relative overflow-hidden">
          {selectedOrder ? (
            <div className="relative z-10 flex flex-col h-full animate-in slide-in-from-right duration-500">
               <h3 className="text-3xl font-black italic uppercase leading-tight mb-8">{selectedOrder.nombreCliente}</h3>

               <div className="flex-1 space-y-8">
                  {(!selectedOrder.idRepartidor || selectedOrder.estado === EstadoPedido.PENDIENTE) ? (
                    <div className="space-y-6">
                       <p className="text-[9px] font-black text-white/30 uppercase tracking-widest border-b border-white/5 pb-4">Asignar Socio</p>
                       {availableDrivers.slice(0, 3).map(driver => (
                         <button 
                            key={driver.id}
                            onClick={() => onAssign(selectedOrder.id, driver.id)}
                            className="w-full bg-white/5 p-6 rounded-[2rem] border border-white/5 flex items-center justify-between hover:bg-plus-blue/20 transition-all group"
                         >
                            <span className="font-black italic uppercase text-xs">{driver.nombre}</span>
                            <span className="text-plus-blue group-hover:text-white">→</span>
                         </button>
                       ))}
                    </div>
                  ) : (
                    <div className="bg-white/5 p-10 rounded-[3rem] text-center">
                       <p className="text-[10px] font-black text-plus-blue uppercase mb-4 tracking-widest">En Proceso</p>
                       <p className="text-xl font-bold italic">Socio asignado con éxito</p>
                    </div>
                  )}
               </div>

               <button onClick={() => setSelectedId(null)} className="mt-10 w-full py-5 bg-white/5 rounded-2xl text-[9px] font-black uppercase tracking-widest">Cerrar Detalle</button>
            </div>
          ) : (
            <div className="flex-1 flex flex-col items-center justify-center text-center opacity-10">
               <p className="text-[10rem] italic font-black">P+</p>
               <p className="text-xl font-black uppercase tracking-[0.5em] italic">Neural Node</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default OrderManagementView;
